package bead

import (
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

const (
	doctorFindingKindOversizedField       = "oversized_field"
	doctorFindingKindParentAncestorInDeps = "parent_ancestor_in_deps"
	doctorFindingKindDanglingDep          = "dangling_dep"
	doctorFindingKindUnparseableLine      = "unparseable_line"
)

// DoctorFinding reports a single bead doctor issue. Findings cover oversized
// field values, dependency edges that point back into the bead's parent chain,
// and line-level parse failures.
type DoctorFinding struct {
	Kind         string   `json:"kind,omitempty"`
	BeadID       string   `json:"bead_id"`
	FieldPath    string   `json:"field_path"`
	TargetID     string   `json:"target_id,omitempty"`
	DependencyID string   `json:"dependency_id,omitempty"`
	AncestorID   string   `json:"ancestor_id,omitempty"`
	ParentChain  []string `json:"parent_chain,omitempty"`
	SizeBytes    int      `json:"size_bytes,omitempty"`
	SampleHead   string   `json:"sample_head,omitempty"`
}

// DoctorReport is the output of BeadDoctor — an ordered list of findings.
type DoctorReport struct {
	Path     string
	Findings []DoctorFinding
}

// Clean is true when there are no findings.
func (r DoctorReport) Clean() bool { return len(r.Findings) == 0 }

type doctorRow struct {
	lineNo   int
	rawLine  []byte
	raw      map[string]any
	bead     *Bead
	parseErr error
}

func loadDoctorRows(path string) ([]doctorRow, error) {
	src, err := os.ReadFile(path)
	if err != nil {
		return nil, err
	}

	lines := bytes.Split(src, []byte{'\n'})
	rows := make([]doctorRow, 0, len(lines))
	for i, line := range lines {
		trimmed := bytes.TrimSpace(line)
		if len(trimmed) == 0 {
			continue
		}
		row := doctorRow{
			lineNo:  i + 1,
			rawLine: append([]byte(nil), line...),
		}
		if err := json.Unmarshal(trimmed, &row.raw); err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		bead, err := unmarshalBead(trimmed)
		if err != nil {
			row.parseErr = err
			rows = append(rows, row)
			continue
		}
		row.bead = &bead
		rows = append(rows, row)
	}
	return rows, nil
}

// BeadDoctor scans a beads.jsonl file and returns every oversized field and
// every dependency edge that points back into the bead's parent chain.
// Lines that fail to parse are reported as a single finding with
// Kind=unparseable_line and the raw line as the sample.
func BeadDoctor(path string) (DoctorReport, error) {
	report := DoctorReport{Path: path}
	rows, err := loadDoctorRows(path)
	if err != nil {
		return report, err
	}

	byID := make(map[string]*Bead, len(rows))
	for _, row := range rows {
		if row.bead == nil || row.bead.ID == "" {
			continue
		}
		byID[row.bead.ID] = row.bead
	}

	// knownIDs is the set of all bead IDs that a dependency may legitimately
	// reference: the active file plus the archive sibling (closed beads migrate
	// there but stay valid dependency targets). A dependency whose target is in
	// neither is dangling — it can never be satisfied, so it blocks readiness
	// forever. Archive presence is best-effort; an absent archive just means
	// every target is checked against the active file.
	knownIDs := make(map[string]struct{}, len(byID))
	for id := range byID {
		knownIDs[id] = struct{}{}
	}
	for id := range loadArchiveBeadIDs(path) {
		knownIDs[id] = struct{}{}
	}

	for _, row := range rows {
		if row.parseErr != nil {
			report.Findings = append(report.Findings, DoctorFinding{
				Kind:       doctorFindingKindUnparseableLine,
				BeadID:     fmt.Sprintf("line %d (unparseable)", row.lineNo),
				FieldPath:  "line",
				SizeBytes:  len(bytes.TrimSpace(row.rawLine)),
				SampleHead: firstN(string(bytes.TrimSpace(row.rawLine)), 80),
			})
			continue
		}
		if row.bead == nil {
			continue
		}
		report.Findings = append(report.Findings, oversizedFieldFindings(row.bead)...)
		report.Findings = append(report.Findings, parentAncestorDepFindings(row.bead, byID)...)
		report.Findings = append(report.Findings, danglingDepFindings(row.bead, knownIDs)...)
	}

	sortDoctorFindings(report.Findings)
	return report, nil
}

func oversizedFieldFindings(b *Bead) []DoctorFinding {
	findings := make([]DoctorFinding, 0, 5)
	if b == nil {
		return findings
	}
	for _, field := range []string{"description", "acceptance", "notes"} {
		if s := beadFieldString(b, field); len(s) > MaxFieldBytes {
			findings = append(findings, DoctorFinding{
				Kind:       doctorFindingKindOversizedField,
				BeadID:     b.ID,
				FieldPath:  field,
				SizeBytes:  len(s),
				SampleHead: firstN(s, 80),
			})
		}
	}
	for i, ev := range decodeBeadEvents(b.Extra["events"]) {
		for _, field := range []string{"body", "summary"} {
			if s := beadEventString(ev, field); len(s) > MaxFieldBytes {
				findings = append(findings, DoctorFinding{
					Kind:       doctorFindingKindOversizedField,
					BeadID:     b.ID,
					FieldPath:  fmt.Sprintf("events[%d].%s", i, field),
					SizeBytes:  len(s),
					SampleHead: firstN(s, 80),
				})
			}
		}
	}
	return findings
}

func beadFieldString(b *Bead, field string) string {
	switch field {
	case "description":
		return b.Description
	case "acceptance":
		return b.Acceptance
	case "notes":
		return b.Notes
	default:
		return ""
	}
}

func beadEventString(ev BeadEvent, field string) string {
	switch field {
	case "body":
		return ev.Body
	case "summary":
		return ev.Summary
	default:
		return ""
	}
}

func parentAncestorDepFindings(b *Bead, byID map[string]*Bead) []DoctorFinding {
	if b == nil {
		return nil
	}
	chain, _ := beadParentChain(byID, b.Parent)
	if len(chain) == 0 || len(b.Dependencies) == 0 {
		return nil
	}
	ancestorSet := make(map[string]struct{}, len(chain))
	for _, ancestorID := range chain {
		ancestorSet[ancestorID] = struct{}{}
	}

	findings := make([]DoctorFinding, 0, len(b.Dependencies))
	for i, dep := range b.Dependencies {
		if _, ok := ancestorSet[dep.DependsOnID]; !ok {
			continue
		}
		findings = append(findings, DoctorFinding{
			Kind:         doctorFindingKindParentAncestorInDeps,
			BeadID:       b.ID,
			FieldPath:    fmt.Sprintf("dependencies[%d].depends_on_id", i),
			TargetID:     dep.DependsOnID,
			DependencyID: dep.DependsOnID,
			AncestorID:   dep.DependsOnID,
			ParentChain:  append([]string(nil), chain...),
			SampleHead:   strings.Join(chain, " -> "),
		})
	}
	return findings
}

// danglingDepFindings flags dependency edges whose target bead exists in
// neither the active file nor the archive. Such an edge can never be satisfied
// (its target will never reach status=closed because it does not exist), so the
// referring bead is blocked from readiness permanently. These accumulate when a
// tracker merge unions in dependency edges from a branch/worktree whose child
// bead records were dropped, or when a malformed/worktree-prefixed child ID is
// written. Mutually exclusive with parent_ancestor_in_deps: an ancestor target
// must exist to be in the parent chain, a dangling target does not exist.
func danglingDepFindings(b *Bead, knownIDs map[string]struct{}) []DoctorFinding {
	if b == nil || len(b.Dependencies) == 0 {
		return nil
	}
	findings := make([]DoctorFinding, 0, len(b.Dependencies))
	for i, dep := range b.Dependencies {
		target := strings.TrimSpace(dep.DependsOnID)
		if target == "" {
			continue
		}
		if _, ok := knownIDs[target]; ok {
			continue
		}
		findings = append(findings, DoctorFinding{
			Kind:         doctorFindingKindDanglingDep,
			BeadID:       b.ID,
			FieldPath:    fmt.Sprintf("dependencies[%d].depends_on_id", i),
			TargetID:     target,
			DependencyID: target,
		})
	}
	return findings

package bead

import (
	"bytes"
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestBeadDoctor_CleanFileReportsNothing covers ddx-b695e162 AC #1: a
// beads.jsonl whose fields all fit under MaxFieldBytes produces a clean
// report. The scan must be a no-op on healthy trees — false positives here
// would spam every operator's CI.
func TestBeadDoctor_CleanFileReportsNothing(t *testing.T) {
	path := filepath.Join(t.TempDir(), "beads.jsonl")
	line := `{"id":"ddx-ok","title":"fine","type":"task","status":"open","priority":2,"description":"normal","labels":[],"deps":[],"created_at":"2026-01-01T00:00:00Z","updated_at":"2026-01-01T00:00:00Z"}`
	require.NoError(t, os.WriteFile(path, []byte(line+"\n"), 0o644))

	report, err := BeadDoctor(path)
	require.NoError(t, err)
	assert.True(t, report.Clean())
	assert.Empty(t, report.Findings)
}

// TestBeadDoctorValidGraphSnapshotClean covers the clean-tracker regression
// contract using the existing bd_export_with_labels_events.jsonl snapshot.
// The fixture is a pre-existing tracker snapshot with parent/dependency
// structure; doctor must treat it as clean when no field exceeds MaxFieldBytes.
func TestBeadDoctorValidGraphSnapshotClean(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	path := filepath.Join(ddxDir, "beads.jsonl")

	fixture, err := os.ReadFile(filepath.Join("testdata", "bd_export_with_labels_events.jsonl"))
	require.NoError(t, err)
	// The snapshot's sole bead (bd-fixture-1) depends on bd-fixture-dep; include
	// that target so the graph is referentially complete. A valid graph has its
	// dependency targets present — an edge to an absent target is a dangling_dep
	// finding (see TestBeadDoctor_DetectsAndFixesDanglingDep).
	depTarget := []byte("\n" + `{"id":"bd-fixture-dep","title":"dep target","issue_type":"task","status":"closed","priority":2}` + "\n")
	require.NoError(t, os.WriteFile(path, append(append([]byte(nil), fixture...), depTarget...), 0o644))

	report, err := BeadDoctor(path)
	require.NoError(t, err)
	assert.True(t, report.Clean())
	assert.Empty(t, report.Findings)
}

// TestBeadDoctor_DetectsAndFixesDanglingDep covers the dangling-dependency
// finding: an edge whose target bead exists in neither the active file nor the
// archive is flagged, and --fix prunes it (these edges otherwise block the
// referrer from readiness forever, since the target can never close).
func TestBeadDoctor_DetectsAndFixesDanglingDep(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	path := filepath.Join(ddxDir, "beads.jsonl")
	lines := strings.Join([]string{
		`{"id":"ddx-referrer","title":"t","issue_type":"task","status":"open","priority":2,"dependencies":[{"depends_on_id":"ddx-ghost"},{"depends_on_id":"ddx-real"}]}`,
		`{"id":"ddx-real","title":"real","issue_type":"task","status":"closed","priority":2}`,
	}, "\n") + "\n"
	require.NoError(t, os.WriteFile(path, []byte(lines), 0o644))

	report, err := BeadDoctor(path)
	require.NoError(t, err)
	var dangling []DoctorFinding
	for _, f := range report.Findings {
		if f.Kind == doctorFindingKindDanglingDep {
			dangling = append(dangling, f)
		}
	}
	require.Len(t, dangling, 1, "exactly the ghost edge is dangling")
	assert.Equal(t, "ddx-referrer", dangling[0].BeadID)
	assert.Equal(t, "ddx-ghost", dangling[0].TargetID)

	_, err = BeadDoctorFix(path, nil)
	require.NoError(t, err)

	fixed, err := BeadDoctor(path)
	require.NoError(t, err)
	assert.Empty(t, fixed.Findings, "second pass is clean (idempotent)")

	// The real, closed dependency must survive; only the ghost edge is pruned.
	repaired, err := loadDoctorRows(path)
	require.NoError(t, err)
	var referrer *Bead
	for _, r := range repaired {
		if r.bead != nil && r.bead.ID == "ddx-referrer" {
			referrer = r.bead
		}
	}
	require.NotNil(t, referrer)
	require.Len(t, referrer.Dependencies, 1)
	assert.Equal(t, "ddx-real", referrer.Dependencies[0].DependsOnID)
}

// TestBeadDoctor_ArchivedDepTargetIsNotDangling covers archive-awareness: a
// dependency on a closed bead that has migrated to beads-archive.jsonl is a
// legitimate target and must NOT be flagged as dangling.
func TestBeadDoctor_ArchivedDepTargetIsNotDangling(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	path := filepath.Join(ddxDir, "beads.jsonl")
	require.NoError(t, os.WriteFile(path,
		[]byte(`{"id":"ddx-referrer","title":"t","issue_type":"task","status":"open","priority":2,"dependencies":[{"depends_on_id":"ddx-archived"}]}`+"\n"), 0o644))
	require.NoError(t, os.WriteFile(filepath.Join(ddxDir, "beads-archive.jsonl"),
		[]byte(`{"id":"ddx-archived","title":"old","issue_type":"task","status":"closed","priority":2}`+"\n"), 0o644))

	report, err := BeadDoctor(path)
	require.NoError(t, err)
	for _, f := range report.Findings {
		assert.NotEqual(t, doctorFindingKindDanglingDep, f.Kind, "archived target is not dangling")
	}
}

// TestBeadDoctor_DetectsOversizedFields covers ddx-b695e162 AC #1: scanner
// reports every field on every bead that exceeds the cap. Synthesizes a
// description longer than MaxFieldBytes and an event body ditto so both
// code paths (top-level fields + nested event fields) are exercised.
func TestBeadDoctor_DetectsOversizedFields(t *testing.T) {
	path := filepath.Join(t.TempDir(), "beads.jsonl")
	huge := strings.Repeat("x", MaxFieldBytes+100)
	bead := map[string]any{
		"id":          "ddx-oversized",
		"title":       "oversized",
		"type":        "task",
		"status":      "open",
		"priority":    2,
		"description": huge,
		"labels":      []string{},
		"deps":        []string{},
		"events": []any{
			map[string]any{"kind": "review", "summary": "APPROVE", "body": huge},
		},
		"created_at": "2026-01-01T00:00:00Z",
		"updated_at": "2026-01-01T00:00:00Z",
	}
	encoded, err := json.Marshal(bead)
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(path, append(encoded, '\n'), 0o644))

	report, err := BeadDoctor(path)
	require.NoError(t, err)
	require.Len(t, report.Findings, 2, "both description and events[0].body must be flagged — partial detection would hide the tracker-corruption surface")

	paths := []string{report.Findings[0].FieldPath, report.Findings[1].FieldPath}
	assert.Contains(t, paths, "description")
	assert.Contains(t, paths, "events[0].body")
	for _, f := range report.Findings {
		assert.Equal(t, "ddx-oversized", f.BeadID)
		assert.Greater(t, f.SizeBytes, MaxFieldBytes, "reported size must exceed the cap — the whole point of the finding")
	}
}

// TestBeadDoctorFix_RewriteIsIdempotent covers ddx-b695e162 AC #3: a tree
// that has been repaired stays clean on subsequent --fix runs. Non-idempotent
// repair would re-process the already-capped field and accumulate artifact
// sidecars on every run.
func TestBeadDoctorFix_RewriteIsIdempotent(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	path := filepath.Join(ddxDir, "beads.jsonl")

	huge := strings.Repeat("A", MaxFieldBytes+10)
	bead := map[string]any{
		"id":          "ddx-fix-idempotent",
		"title":       "fix me",
		"type":        "task",
		"status":      "open",
		"priority":    2,
		"description": huge,
		"labels":      []string{},
		"deps":        []string{},
		"created_at":  "2026-01-01T00:00:00Z",
		"updated_at":  "2026-01-01T00:00:00Z",
	}
	encoded, err := json.Marshal(bead)
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(path, append(encoded, '\n'), 0o644))

	fixedAt := time.Date(2026, 4, 20, 12, 0, 0, 0, time.UTC)
	report1, err := BeadDoctorFix(path, func() time.Time { return fixedAt })
	require.NoError(t, err)
	require.False(t, report1.Clean(), "first fix must find the oversized field")

	report2, err := BeadDoctorFix(path, func() time.Time { return fixedAt.Add(time.Hour) })
	require.NoError(t, err)
	assert.True(t, report2.Clean(), "after a --fix pass the tree must be clean so repeated runs do not re-repair the same rows")
}

// TestBeadDoctorFix_WritesBackupAndArtifact covers ddx-b695e162 AC #2: a
// --fix run writes a backup before touching the source and persists full
// overflow content as an artifact sidecar. Operators MUST be able to recover
// the pre-fix state and audit the truncated payload.
func TestBeadDoctorFix_WritesBackupAndArtifact(t *testing.T) {
	dir := t.TempDir()
	ddxDir := filepath.Join(dir, ddxroot.DirName)
	require.NoError(t, os.MkdirAll(ddxDir, 0o755))
	path := filepath.Join(ddxDir, "beads.jsonl")

	huge := strings.Repeat("B", MaxFieldBytes+100)
	bead := map[string]any{
		"id":          "ddx-artifact-test",
		"title":       "with artifact",
		"type":        "task",
		"status":      "open",
		"priority":    2,
		"description": huge,
		"labels":      []string{},
		"deps":        []string{},
		"created_at":  "2026-01-01T00:00:00Z",
		"updated_at":  "2026-01-01T00:00:00Z",
	}
	encoded, err := json.Marshal(bead)
	require.NoError(t, err)
	require.NoError(t, os.WriteFile(path, append(encoded, '\n'), 0o644))

	fixedAt := time.Date(2026, 4, 20, 12, 0, 0, 0, time.UTC)
	_, err = BeadDoctorFix(path, func() time.Time { return fixedAt })
	require.NoError(t, err)

	// Backup exists with the original huge content intact.
	backups, err := os.ReadDir(filepath.Join(ddxDir, "backups"))
	require.NoError(t, err)
	require.Len(t, backups, 1, "exactly one backup must be written per --fix invocation")
	backupContents, err := os.ReadFile(filepath.Join(ddxDir, "backups", backups[0].Name()))
	require.NoError(t, err)
	assert.Contains(t, string(backupContents), huge[:200],
		"backup must preserve the pre-fix payload byte-for-byte — otherwise recovery is impossible")

	// Artifact sidecar holds the full original field.
	artifactDir := filepath.Join(ddxDir, "executions", "ddx-artifact-test", "repair-20260420T120000")
	entries, err := os.ReadDir(artifactDir)
	require.NoError(t, err, "repair dir must be created per bead per --fix invocation")
	require.Len(t, entries, 1, "one sidecar per oversized field")
	artifactContents, err := os.ReadFile(filepath.Join(artifactDir, entries[0].Name()))
	require.NoError(t, err)
	assert.Equal(t, huge, string(artifactContents),
		"sidecar must preserve the original oversized field verbatim — this is the forensic trail that makes truncation safe")

	// Repaired source has a repair event recording what was done.
	repaired, err := os.ReadFile(path)
	require.NoError(t, err)
	var parsed map[string]any
	require.NoError(t, json.Unmarshal(repaired, &parsed))
	events, ok := parsed["events"].([]any)
	require.True(t, ok, "repair event must be appended to the rewritten bead")
	require.Len(t, events, 1)
	ev := events[0].(map[string]any)
	assert.Equal(t, "repair", ev["kind"])

package bead

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"reflect"
	"sort"
	"strings"
	"time"
)

// TrackerMergeReport describes a JSONL three-way tracker merge.
type TrackerMergeReport struct {
	TotalRecords    int
	PreservedOurs   int
	PreservedTheirs int
	MergedRecords   int
	ScalarConflicts []TrackerScalarConflict
}

// TrackerScalarConflict records a same-field conflict resolved by the merge
// policy. The command intentionally reports these choices instead of hiding
// them behind a silent latest-wins fold.
type TrackerScalarConflict struct {
	ID     string
	Field  string
	Choice string
	Reason string
}

type trackerRecord map[string]any

// MergeTrackerConflictJSONL merges base/ours/theirs bead JSONL content.
// Records are keyed by id. Append-only event and dependency lists are unioned;
// scalar fields use a three-way merge with deterministic timestamp/ours
// tie-breaking for true conflicts.
func MergeTrackerConflictJSONL(baseData, oursData, theirsData []byte) ([]byte, TrackerMergeReport, error) {
	base, err := parseTrackerRecords(baseData, "base")
	if err != nil {
		return nil, TrackerMergeReport{}, err
	}
	ours, err := parseTrackerRecords(oursData, "ours")
	if err != nil {
		return nil, TrackerMergeReport{}, err
	}
	theirs, err := parseTrackerRecords(theirsData, "theirs")
	if err != nil {
		return nil, TrackerMergeReport{}, err
	}

	report := TrackerMergeReport{}
	ids := mergeTrackerIDs(base, ours, theirs)
	merged := make([]trackerRecord, 0, len(ids))
	for _, id := range ids {
		b, hasBase := base[id]
		o, hasOurs := ours[id]
		t, hasTheirs := theirs[id]

		switch {
		case hasOurs && !hasTheirs:
			merged = append(merged, cloneTrackerRecord(o))
			if !hasBase {
				report.PreservedOurs++
			}
		case hasTheirs && !hasOurs:
			merged = append(merged, cloneTrackerRecord(t))
			if !hasBase {
				report.PreservedTheirs++
			}
		case hasOurs && hasTheirs:
			if trackerRecordEqual(o, t) {
				merged = append(merged, cloneTrackerRecord(o))
				continue
			}
			rec, conflicts := mergeTrackerRecord(id, b, o, t, hasBase)
			merged = append(merged, rec)
			report.MergedRecords++
			report.ScalarConflicts = append(report.ScalarConflicts, conflicts...)
		default:
			merged = append(merged, cloneTrackerRecord(b))
		}
	}

	out, err := encodeTrackerJSONL(merged)
	if err != nil {
		return nil, TrackerMergeReport{}, err
	}
	if err := ValidateTrackerJSONLUnique(out); err != nil {
		return nil, TrackerMergeReport{}, err
	}
	report.TotalRecords = len(merged)
	return out, report, nil
}

// ValidateTrackerJSONLUnique checks that content is valid bead JSONL with one
// record per id.
func ValidateTrackerJSONLUnique(data []byte) error {
	_, err := parseTrackerRecords(data, "merged")
	return err
}

func parseTrackerRecords(data []byte, side string) (map[string]trackerRecord, error) {
	scanner := bufio.NewScanner(bytes.NewReader(data))
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)

	records := make(map[string]trackerRecord)
	lineNo := 0
	for scanner.Scan() {
		lineNo++
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}
		var rec trackerRecord
		if err := json.Unmarshal([]byte(line), &rec); err != nil {
			return nil, fmt.Errorf("bead merge: parse %s line %d: %w", side, lineNo, err)
		}
		id, _ := rec["id"].(string)
		if strings.TrimSpace(id) == "" {
			return nil, fmt.Errorf("bead merge: parse %s line %d: missing id", side, lineNo)
		}
		if _, exists := records[id]; exists {
			return nil, fmt.Errorf("bead merge: parse %s line %d: duplicate id %s", side, lineNo, id)
		}
		records[id] = rec
	}
	if err := scanner.Err(); err != nil {
		return nil, fmt.Errorf("bead merge: scan %s: %w", side, err)
	}
	return records, nil
}

